async def handler(nexus, inputs, event):
    types = await nexus.list_types()
    counts = {}
    for t in types or []:
        name = t.get('name') or t.get('display_name')
        try:
            res = await nexus.query(object_type=name, limit=1)
            counts[name] = (res or {}).get('total') or (res or {}).get('count') or len((res or {}).get('records') or [])
        except Exception as e:
            counts[name] = 'error'
    snapshot = {'when': datetime.datetime.utcnow().isoformat(), 'counts': counts}
    await nexus.kv_set('latest_summary', snapshot)
    return snapshot
